// Evidence: httpsts-overload-recovery-evidence-tmwmke
// Competency: httpsts-overload-recovery-evidence.
// Case 6422: partner integration using an older generated TypeScript client.
// Operating constraint: preserve response ownership after a client abort.
// Changed case: remove one trusted proxy hop and recompute authority from the socket boundary.
function evidence_httpsts_overload_recovery_evidence_tmwmke(active: number, capacity: number, queueDepth: number, tenantTokens: number): { admit: boolean; offloadCpu: boolean; reason: string } {
  if (active < 0 || capacity <= 0 || queueDepth < 0) {
    return { admit: false, offloadCpu: false, reason: "invalid-budget" };
  }
  if (tenantTokens <= 0) return { admit: false, offloadCpu: false, reason: "tenant-rate" };
  const admit = active < capacity && queueDepth < capacity * 2;
  return { admit, offloadCpu: admit && active > capacity / 2, reason: admit ? "capacity" : "shed" };
}
